import React, { useState, useEffect, useRef } from 'react';
import './App.css';
import { Save, Calendar, FileText, ChevronRight, Flag, Clock, HelpCircle, Info, Loader, Trash2, X } from 'lucide-react';

function App() {
  const [formData, setFormData] = useState({
    week: '',
    type: '',
    date: '',
    action: ''
  });

  const [weeks, setWeeks] = useState([]);
  const [types, setTypes] = useState([]);
  const [actions, setActions] = useState([]);
  const [expandedNodes, setExpandedNodes] = useState(new Set());
  const [contextMenu, setContextMenu] = useState({ visible: false, x: 0, y: 0, actionId: null });
  const [actionStatuses, setActionStatuses] = useState({});
  const [excludedFromReport, setExcludedFromReport] = useState(new Set());
  const dateInputRef = useRef(null);
  const contextMenuRef = useRef(null);

  useEffect(() => {
    // Load weeks from text file
    fetch('/data/weeks.txt')
      .then(response => response.text())
      .then(data => {
        const weekList = data.split('\n').filter(line => line.trim());
        setWeeks(weekList);
      })
      .catch(error => {
        console.error('Error loading weeks:', error);
        // Fallback data
        setWeeks(['1. Hafta', '2. Hafta', '3. Hafta', '4. Hafta']);
      });

    // Load types from text file
    fetch('/data/types.txt')
      .then(response => response.text())
      .then(data => {
        const typeList = data.split('\n').filter(line => line.trim());
        setTypes(typeList);
      })
      .catch(error => {
        console.error('Error loading types:', error);
        // Fallback data
        setTypes(['Planlama', 'Geliştirme', 'Test', 'Dokümantasyon']);
      });
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleCalendarClick = () => {
    dateInputRef.current?.showPicker();
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.week || !formData.type || !formData.date || !formData.action) {
      alert('Lütfen tüm alanları doldurun.');
      return;
    }

    const newAction = {
      id: Date.now(),
      ...formData,
      timestamp: new Date().toLocaleString('tr-TR')
    };

    setActions(prev => [...prev, newAction]);

    // Reset form
    setFormData({
      week: '',
      type: '',
      date: '',
      action: ''
    });
  };

  const toggleNode = (nodeId) => {
    setExpandedNodes(prev => {
      const newSet = new Set(prev);
      if (newSet.has(nodeId)) {
        newSet.delete(nodeId);
      } else {
        newSet.add(nodeId);
      }
      return newSet;
    });
  };

  const groupActionsByWeek = () => {
    const grouped = {};
    actions.forEach(action => {
      if (!grouped[action.week]) {
        grouped[action.week] = [];
      }
      grouped[action.week].push(action);
    });
    return grouped;
  };

  const groupedActions = groupActionsByWeek();

  return (
    <div className="app-container">
      <header className="header">
        <h1>Haftalık Aksiyon Takibi</h1>
      </header>

      <div className="content">
        <div className="left-section">
          <div className="card">
            <h2 className="card-title">Yeni Aksiyon Ekle</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Week</label>
                <select
                  className="form-select"
                  name="week"
                  value={formData.week}
                  onChange={handleInputChange}
                >
                  <option value="">Hafta seçin...</option>
                  {weeks.map((week, index) => (
                    <option key={index} value={week}>{week}. Hafta</option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Type</label>
                <select
                  className="form-select"
                  name="type"
                  value={formData.type}
                  onChange={handleInputChange}
                >
                  <option value="">Tür seçin...</option>
                  {types.map((type, index) => (
                    <option key={index} value={type}>{type}</option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Date</label>
                <div className="input-with-icon">
                  <input
                    type="date"
                    className="form-control"
                    name="date"
                    ref={dateInputRef}
                    value={formData.date}
                    onChange={handleInputChange}
                    placeholder="gg.aa.yyyy"
                  />
                  <Calendar className="input-icon" size={18} onClick={handleCalendarClick} style={{ cursor: 'pointer', pointerEvents: 'auto' }} />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Action</label>
                <textarea
                  className="form-textarea"
                  name="action"
                  value={formData.action}
                  onChange={handleInputChange}
                  placeholder="Aksiyonu detaylı olarak yazın..."
                />
              </div>

              <button type="submit" className="btn btn-primary">
                <Save size={16} />
                Save
              </button>
            </form>
          </div>

          {actions.length > 0 && (
            <div className="card">
              <h2 className="card-title">Kaydedilen Aksiyonlar</h2>
              <div className="action-list">
                {actions.map((action) => (
                  <div key={action.id} className="action-row">
                    <div className="action-row-header">
                      <span className="action-row-week">{action.week}. Hafta</span>
                      <span className="action-row-type">{action.type}</span>
                    </div>
                    <div className="action-row-date">{action.date}</div>
                    <div className="action-row-text">{action.action}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="right-section">
          <div className="card">
            <h2 className="card-title">Display Weekly Report</h2>
            <div className="report-section">
              <div className="report-content">
                <p className="report-text">
                  Bu hafta toplam {actions.length} aksiyon kaydedildi.
                </p>
              </div>
            </div>
          </div>

          <div className="card">
            <h2 className="card-title">Team Actions</h2>
            {actions.length === 0 ? (
              <div className="empty-state">
                <FileText className="empty-state-icon" size={48} />
                <h3>Henüz kayıt yok</h3>
                <p>Yeni bir aksiyon ekleyerek başlayın</p>
              </div>
            ) : (
              <div className="tree-view">
                {Object.entries(groupedActions).map(([week, weekActions]) => (
                  <div key={week} className="tree-node">
                    <div 
                      className="tree-node-header"
                      onClick={() => toggleNode(week)}
                    >
                      <span className="tree-node-title">{week}. Hafta ({weekActions.length} aksiyon)</span>
                      <ChevronRight 
                        className={`tree-node-toggle ${expandedNodes.has(week) ? 'expanded' : ''}`} 
                        size={18} 
                      />
                    </div>
                    <div className={`tree-node-content ${!expandedNodes.has(week) ? 'hidden' : ''}`}>
                      {weekActions.map(action => (
                        <div key={action.id} style={{ marginBottom: '15px' }}>
                          <div className="action-detail">
                            <span className="action-detail-label">Tür:</span>
                            <span className="action-detail-value">{action.type}</span>
                          </div>
                          <div className="action-detail">
                            <span className="action-detail-label">Tarih:</span>
                            <span className="action-detail-value">{action.date}</span>
                          </div>
                          <div className="action-detail">
                            <span className="action-detail-label">Aksiyon:</span>
                            <span className="action-detail-value">{action.action}</span>
                          </div>
                          <div className="action-detail">
                            <span className="action-detail-label">Eklenme:</span>
                            <span className="action-detail-value">{action.timestamp}</span>
                          </div>
                          <hr style={{ margin: '10px 0', border: 'none', borderTop: '1px solid #eee' }} />
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
